<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Kanban Board</title>
<style>
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  body {
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
    background: #0f172a;
    color: #e2e8f0;
    min-height: 100vh;
    padding: 32px 24px;
  }

  h1 {
    text-align: center;
    font-size: 1.75rem;
    font-weight: 700;
    letter-spacing: -0.02em;
    color: #f8fafc;
    margin-bottom: 28px;
  }

  .add-bar {
    display: flex;
    gap: 10px;
    max-width: 480px;
    margin: 0 auto 36px;
  }

  #new-card {
    flex: 1;
    padding: 10px 14px;
    border-radius: 8px;
    border: 1.5px solid #334155;
    background: #1e293b;
    color: #f1f5f9;
    font-size: 0.95rem;
    outline: none;
    transition: border-color 0.15s;
  }

  #new-card:focus { border-color: #6366f1; }
  #new-card::placeholder { color: #64748b; }

  #add-card {
    padding: 10px 20px;
    border-radius: 8px;
    border: none;
    background: #6366f1;
    color: #fff;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: background 0.15s, transform 0.1s;
  }

  #add-card:hover { background: #4f46e5; }
  #add-card:active { transform: scale(0.97); }

  .board {
    display: flex;
    gap: 20px;
    align-items: flex-start;
    max-width: 1100px;
    margin: 0 auto;
  }

  .column {
    flex: 1;
    background: #1e293b;
    border-radius: 14px;
    padding: 0;
    min-height: 400px;
    display: flex;
    flex-direction: column;
    border: 1.5px solid #334155;
    transition: border-color 0.15s;
  }

  .column.drag-over {
    border-color: #6366f1;
    background: #1e2d45;
  }

  .col-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 16px 18px 14px;
    border-bottom: 1.5px solid #334155;
  }

  .col-header h2 {
    font-size: 0.9rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.08em;
  }

  #col-todo .col-header h2 { color: #94a3b8; }
  #col-doing .col-header h2 { color: #f59e0b; }
  #col-done .col-header h2 { color: #22c55e; }

  .count {
    font-size: 0.78rem;
    font-weight: 700;
    background: #334155;
    color: #94a3b8;
    border-radius: 12px;
    padding: 2px 9px;
    min-width: 24px;
    text-align: center;
  }

  .card-container {
    padding: 12px;
    display: flex;
    flex-direction: column;
    gap: 10px;
    flex: 1;
    min-height: 60px;
  }

  .card {
    background: #0f172a;
    border: 1.5px solid #334155;
    border-radius: 10px;
    padding: 12px 14px;
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 10px;
    cursor: grab;
    transition: box-shadow 0.15s, border-color 0.15s, transform 0.1s;
    user-select: none;
  }

  .card:hover {
    border-color: #475569;
    box-shadow: 0 4px 16px rgba(0,0,0,0.4);
  }

  .card.dragging {
    opacity: 0.4;
    transform: scale(0.97);
    cursor: grabbing;
  }

  .card-title {
    font-size: 0.9rem;
    line-height: 1.45;
    color: #e2e8f0;
    word-break: break-word;
    flex: 1;
  }

  .card-del {
    flex-shrink: 0;
    background: none;
    border: none;
    color: #475569;
    cursor: pointer;
    font-size: 1rem;
    line-height: 1;
    padding: 0 2px;
    border-radius: 4px;
    transition: color 0.15s, background 0.15s;
    margin-top: 1px;
  }

  .card-del:hover {
    color: #f87171;
    background: #1e293b;
  }

  @media (max-width: 640px) {
    .board { flex-direction: column; }
  }
</style>
</head>
<body>

<h1>Kanban Board</h1>

<div class="add-bar">
  <input id="new-card" type="text" placeholder="Add a new card…" maxlength="200">
  <button id="add-card">Add Card</button>
</div>

<div class="board">
  <div class="column" id="col-todo">
    <div class="col-header">
      <h2>To Do</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-doing">
    <div class="col-header">
      <h2>Doing</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
  <div class="column" id="col-done">
    <div class="col-header">
      <h2>Done</h2>
      <span class="count">0</span>
    </div>
    <div class="card-container"></div>
  </div>
</div>

<script>
  const STORAGE_KEY = 'kanban_board_v1';
  let draggedCard = null;

  function getColumns() {
    return {
      'col-todo': document.getElementById('col-todo'),
      'col-doing': document.getElementById('col-doing'),
      'col-done': document.getElementById('col-done'),
    };
  }

  function getContainer(colEl) {
    return colEl.querySelector('.card-container');
  }

  function updateCount(colEl) {
    const count = colEl.querySelectorAll('.card').length;
    colEl.querySelector('.count').textContent = count;
  }

  function saveState() {
    const cols = getColumns();
    const state = {};
    for (const [id, colEl] of Object.entries(cols)) {
      state[id] = Array.from(colEl.querySelectorAll('.card')).map(c =>
        c.querySelector('.card-title').textContent
      );
    }
    localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
  }

  function createCard(title) {
    const card = document.createElement('div');
    card.className = 'card';
    card.draggable = true;

    const titleEl = document.createElement('span');
    titleEl.className = 'card-title';
    titleEl.textContent = title;

    const del = document.createElement('button');
    del.className = 'card-del';
    del.textContent = '✕';
    del.title = 'Delete card';
    del.addEventListener('click', () => {
      const col = card.closest('.column');
      card.remove();
      updateCount(col);
      saveState();
    });

    card.appendChild(titleEl);
    card.appendChild(del);

    card.addEventListener('dragstart', e => {
      draggedCard = card;
      card.classList.add('dragging');
      e.dataTransfer.effectAllowed = 'move';
    });

    card.addEventListener('dragend', () => {
      card.classList.remove('dragging');
      draggedCard = null;
      document.querySelectorAll('.column').forEach(c => c.classList.remove('drag-over'));
    });

    return card;
  }

  function setupColumn(colEl) {
    colEl.addEventListener('dragover', e => {
      e.preventDefault();
      e.dataTransfer.dropEffect = 'move';
      colEl.classList.add('drag-over');
    });

    colEl.addEventListener('dragleave', e => {
      if (!colEl.contains(e.relatedTarget)) {
        colEl.classList.remove('drag-over');
      }
    });

    colEl.addEventListener('drop', e => {
      e.preventDefault();
      colEl.classList.remove('drag-over');
      if (!draggedCard) return;

      const fromCol = draggedCard.closest('.column');
      const container = getContainer(colEl);

      const afterEl = getDragAfterElement(container, e.clientY);
      if (afterEl) {
        container.insertBefore(draggedCard, afterEl);
      } else {
        container.appendChild(draggedCard);
      }

      if (fromCol && fromCol !== colEl) updateCount(fromCol);
      updateCount(colEl);
      saveState();
    });
  }

  function getDragAfterElement(container, y) {
    const cards = Array.from(container.querySelectorAll('.card:not(.dragging)'));
    return cards.reduce((closest, child) => {
      const box = child.getBoundingClientRect();
      const offset = y - box.top - box.height / 2;
      if (offset < 0 && offset > closest.offset) {
        return { offset, element: child };
      }
      return closest;
    }, { offset: Number.NEGATIVE_INFINITY }).element;
  }

  function loadState() {
    const cols = getColumns();
    const raw = localStorage.getItem(STORAGE_KEY);
    if (!raw) return;
    try {
      const state = JSON.parse(raw);
      for (const [id, titles] of Object.entries(state)) {
        const colEl = cols[id];
        if (!colEl) continue;
        const container = getContainer(colEl);
        for (const title of titles) {
          container.appendChild(createCard(title));
        }
        updateCount(colEl);
      }
    } catch (e) {
      // ignore corrupt storage
    }
  }

  // Init columns
  for (const colEl of Object.values(getColumns())) {
    setupColumn(colEl);
  }

  // Add card button
  document.getElementById('add-card').addEventListener('click', () => {
    const input = document.getElementById('new-card');
    const title = input.value.trim();
    if (!title) return;
    const col = document.getElementById('col-todo');
    getContainer(col).appendChild(createCard(title));
    updateCount(col);
    saveState();
    input.value = '';
    input.focus();
  });

  document.getElementById('new-card').addEventListener('keydown', e => {
    if (e.key === 'Enter') document.getElementById('add-card').click();
  });

  loadState();
</script>
</body>
</html>
